                vec[i] = v0 * fcr - v1 * fci;
                vec[i + 1] = v0 * fci + v1 * fcr;
            }
        }
    }

    fn score(
        state: &mut RunState,
        config: &Config,
        layer: usize,
        head: usize,
        pos: usize,
    ){
        let dim=config.dim;
        let head_size=dim/config.n_heads;
        let kv_dim=(config.dim*config.n_kv_heads)/config.n_heads;
        let kv_mul=config.n_heads/config.n_kv_heads;
