fn argmax(values: &[f32]) -> usize {
    let mut best_idx = 0usize;
    let mut best_val = values[0];

    for (idx, &value) in values.iter().enumerate().skip(1) {
        if value > best_val {
            best_val = value;
            best_idx = idx;
        }
    }

