    // q,kの要素をposが増加するにつれて回転させる
    fn rope(q: &mut [f32],k: &mut [f32],config: &Config,pos: usize) {
        let dim = config.dim;
        let head_size = dim / config.n_heads;
        let kv_dim = (config.dim * config.n_kv_heads) / config.n_heads;

