                    let v_start = loff + t * kv_dim + (head / kv_mul) * head_size;
                    let v_end = v_start + head_size;
                    let v = &value_cache[v_start..v_end];
                    let a = att[t];

                    for i in 0..head_size {
                        xb[i] += a * v[i];
                    }
                }
            });
